from copy import deepcopy
from typing import Any

import yaml
from transformers import AutoConfig

from sglang_omni.config.schema import PipelineConfig
from sglang_omni.models.registry import PIPELINE_CONFIG_REGISTRY
from sglang_omni.utils import (
    architecture_from_hf_config,
    try_resolve_arch_from_mistral_config,
    try_resolve_arch_from_raw_config,
)


def resolve_config_cls_for_model_path(model_path: str):
    """Resolve a PipelineConfig class from HF config metadata."""
    hf_config = None
    try:
        hf_config = AutoConfig.from_pretrained(model_path)
    except (OSError, ValueError, KeyError):
        hf_config = None

    arch = architecture_from_hf_config(hf_config) if hf_config is not None else None
    if arch is None:
        arch = try_resolve_arch_from_raw_config(model_path)
    if arch is None:
        arch = try_resolve_arch_from_mistral_config(model_path)
    if arch is None:
        raise ValueError(f"Could not resolve model architecture for {model_path!r}")
    return PIPELINE_CONFIG_REGISTRY.get_config(arch)


class ConfigManager:
    """
    The ConfigManager is responsible for managing the configuration based on the user CLI arguments, configuration file
    given by the user, and the default configuration for the model. As the omni models have various architectures, setting a uniform
    list of arguments is not feasible. Thus, we take reference from the TorchTitan's configuration management system to allow users to
    dynamically configure their runtime settings.
    """

    def __init__(self, config: PipelineConfig | None = None):
        self.config = config

    def parse_extra_args(self, args: list[str]) -> dict[str, Any]:
        """
        Parse the CLI arguments and return the configuration.
        """
        # we expect the arguments to be key-values pairs
        extra_args = {}
        cur_key, cur_value = None, None
        for arg in args:
            if "=" in arg and cur_key is None and cur_value is None:
                cur_key, cur_value = arg.split("=", 1)
            elif cur_key is None and cur_value is None:
                cur_key = arg
            elif cur_key is not None and cur_value is None:
                # record the key value pair
                cur_value = arg
            else:
                raise ValueError(f"Invalid argument: {arg}")

            if cur_key is not None and cur_value is not None:
                # remove the -- in front of the key
                formatted_key = cur_key.lstrip("-").replace("-", "_")
                extra_args[formatted_key] = cur_value
                cur_key, cur_value = None, None
        if cur_key is not None and cur_value is None:
            raise ValueError(f"Missing value for argument: {cur_key}")
        return extra_args

    def _convert_types(self, extra_args: dict[str, Any]) -> dict[str, Any]:
        """
        Convert the configuration to the inferred data types.
        """
        return {key: _convert_scalar(value) for key, value in extra_args.items()}

    def merge_config(self, extra_args: dict[str, Any]) -> PipelineConfig:
        """
        Merge the configuration and the extra arguments.
        """
        extra_args = self._convert_types(extra_args)
        config_data = self.config.model_dump()
        config_cls = type(self.config)

        cfg_copy = deepcopy(config_data)
        for key, value in extra_args.items():
            current = cfg_copy
            keys = key.split(".")
            for k in keys[:-1]:
                current = _resolve_child(current, k)

            # update the value
            last_key = keys[-1]
            if isinstance(current, list):
                current[_resolve_list_index(current, last_key)] = value
            else:
                current[last_key] = value

        _sync_stage_parallelism_aliases(cfg_copy, set(extra_args))

        # validate the configuration
        merged_config = config_cls(**cfg_copy)
        return merged_config

    @staticmethod
    def from_model_path(model_path: str, variant: str | None = None) -> "ConfigManager":
        """Load config from model path, optionally selecting a variant."""
        import importlib

        config_cls = resolve_config_cls_for_model_path(model_path)

        if variant:
            module = importlib.import_module(config_cls.__module__)
            variants = getattr(module, "Variants", None)
            if variants and variant in variants:
                config_cls = variants[variant]
            else:
                raise ValueError(
                    f"Unknown variant '{variant}' for {config_cls.__name__}"
                )

        config = config_cls(model_path=model_path)
        return ConfigManager(config)

    @staticmethod
    def from_file(file_path: str) -> "ConfigManager":
        """
        Load the configuration from the file path.
        """
        with open(file_path, "r") as f:
            data = yaml.safe_load(f)
        if not isinstance(data, dict):
            raise ValueError(f"Config file {file_path!r} must contain a mapping")

        data = dict(data)
        has_stage_overrides = "stage_overrides" in data
        stage_overrides = data.pop("stage_overrides", {})
        config_cls_str = data["config_cls"]
        config_cls = PIPELINE_CONFIG_REGISTRY.get_config_cls_by_name(config_cls_str)
        config = config_cls(**data)
        if has_stage_overrides:
            config = _apply_stage_overrides(config, stage_overrides)
        return ConfigManager(config)


def _apply_stage_overrides(
    config: PipelineConfig,
    stage_overrides: dict[str, Any],
) -> PipelineConfig:
    """Apply compact file-level runtime overrides by stage name."""

    if not isinstance(stage_overrides, dict):
        raise ValueError(
            "stage_overrides must be a mapping from stage name to overrides"
        )

    config_data = config.model_dump()
    stages = config_data["stages"]
    stage_by_name = {stage["name"]: stage for stage in stages}

    for stage_name, override in stage_overrides.items():
        if stage_name not in stage_by_name:
            raise ValueError(f"stage_overrides references unknown stage {stage_name!r}")
        if not isinstance(override, dict):
            raise ValueError(f"stage_overrides.{stage_name} must be a mapping")

        unsupported = sorted(set(override) - {"runtime"})
        if unsupported:
            raise ValueError(
                f"stage_overrides.{stage_name} supports only runtime overrides; "
                f"got unsupported keys {unsupported}"
            )

        if "runtime" not in override:
            continue
        runtime_override = override["runtime"]
        if not isinstance(runtime_override, dict):
            raise ValueError(f"stage_overrides.{stage_name}.runtime must be a mapping")
        stage = stage_by_name[stage_name]
        stage["runtime"] = _deep_merge_dict(
            stage.get("runtime", {}),
            runtime_override,
        )

    return type(config)(**config_data)


def _deep_merge_dict(base: dict[str, Any], overlay: dict[str, Any]) -> dict[str, Any]:
    merged = deepcopy(base)
    for key, value in overlay.items():
        if isinstance(value, dict) and isinstance(merged.get(key), dict):
            merged[key] = _deep_merge_dict(merged[key], value)
        else:
            merged[key] = value
    return merged


def _sync_stage_parallelism_aliases(
    config_data: dict[str, Any],
    override_keys: set[str],
) -> None:
    """Keep StageConfig.tp_size and parallelism.tp coherent for dotted CLI args."""
    stages = config_data.get("stages")
    if not isinstance(stages, list):
        return

    for index, stage in enumerate(stages):
        if not isinstance(stage, dict):
            continue
        stage_keys = (str(index), stage["name"])
        has_tp_size_override = any(
            f"stages.{key}.tp_size" in override_keys for key in stage_keys
        )
        has_parallelism_override = any(
            f"stages.{key}.parallelism.tp" in override_keys for key in stage_keys
        )
        if has_tp_size_override == has_parallelism_override:
            continue

        if has_tp_size_override:
            parallelism = dict(stage.get("parallelism") or {})
            parallelism["tp"] = stage["tp_size"]
            stage["parallelism"] = parallelism
        else:
            stage["tp_size"] = stage["parallelism"]["tp"]


def _resolve_list_index(items: list[Any], key: str) -> int:
    """Resolve a dotted-path segment to a list index.

    Supports numeric indices (e.g. ``stages.4.tp_size``) as well as stage names
    (e.g. ``stages.thinker.runtime``) when the list contains mappings with a
    ``name`` field.
    """
    if key.isdigit():
        return int(key)

    for index, item in enumerate(items):
        if isinstance(item, dict) and item.get("name") == key:
            return index

    available = [
        item["name"] for item in items if isinstance(item, dict) and "name" in item
    ]
    raise KeyError(
        f"Could not resolve list element {key!r}; expected an integer index "
        f"or one of the named entries {available}"
    )


def _resolve_child(current: Any, key: str) -> Any:
    """Traverse one segment of a dotted config path."""
    if isinstance(current, list):
        return current[_resolve_list_index(current, key)]
    return current[key]


def _convert_scalar(value: Any) -> Any:
    if not isinstance(value, str):
        return value

    lowered = value.lower()
    if lowered == "true":
        return True
    if lowered == "false":
        return False
    if lowered == "none":
        return None

    try:
        return int(value)
    except ValueError:
        pass

    try:
        return float(value)
    except ValueError:
        return value

# SPDX-License-Identifier: Apache-2.0
"""Configuration schema for pipeline wiring."""

from __future__ import annotations

from typing import Any, ClassVar

from pydantic import BaseModel, ConfigDict, Field


class CommConfig(BaseModel):
    """Per-stage communication buffer and Mooncake options.

    Transport selection is owned by ``CommRouter`` from stage locality and
    placement. This config only tunes buffer pools and backend-specific
    connection options for transports the router selects.
    """

    model_config = ConfigDict(extra="forbid")

    slot_size_mb: int = 512
    credits: int = 2
    cuda_ipc_slot_size_kb: int = 64
    cuda_ipc_pool_size_mb: int | None = None
    mooncake_protocol: str = "rdma"
    mooncake_hostname: str | None = None
    mooncake_device_name: str = ""


class EndpointsConfig(BaseModel):
    """Endpoint allocation settings."""

    model_config = ConfigDict(extra="forbid")

    base_path: str = "/tmp/sglang_omni"


class ParallelismConfig(BaseModel):
    """Supported parallelism for one logical stage."""

    model_config = ConfigDict(extra="forbid")

    tp: int = 1

    def model_post_init(self, __context: Any = None) -> None:
        if self.tp < 1:
            raise ValueError("parallelism.tp must be >= 1")


class StageResourceConfig(BaseModel):
    """Placement-resource intent for one stage rank/process."""

    model_config = ConfigDict(extra="forbid")

    total_gpu_memory_fraction: float | None = Field(
        default=None,
        description=(
            "Per-rank/process budget as a fraction of total physical GPU "
            "memory. After TP expansion, each rank contributes this budget to "
            "its assigned GPU."
        ),
    )

    def model_post_init(self, __context: Any = None) -> None:
        value = self.total_gpu_memory_fraction
        if value is not None and not 0.0 < value <= 1.0:
            raise ValueError(
                "runtime.resources.total_gpu_memory_fraction must be in (0, 1]"
            )


class SGLangServerArgsConfig(BaseModel):
    """Typed subset of SGLang ServerArgs exposed through pipeline config."""

    model_config = ConfigDict(extra="forbid")

    mem_fraction_static: float | None = None

    def model_post_init(self, __context: Any = None) -> None:
        value = self.mem_fraction_static
        if value is not None and not 0.0 < value < 1.0:
            raise ValueError(
                "runtime.sglang_server_args.mem_fraction_static must be in (0, 1)"
            )


class StageRuntimeConfig(BaseModel):
    """Typed runtime intent for one stage.

    Backend-specific values stay namespaced. For example,
    sglang_server_args is translated into SGLang ServerArgs by the
    runtime adapter, not by placement planning.
    """

    model_config = ConfigDict(extra="forbid")

    resources: StageResourceConfig = Field(default_factory=StageResourceConfig)
    max_seq_len: int | None = None
    video_fps: float | None = None
    sglang_server_args: SGLangServerArgsConfig = Field(
        default_factory=SGLangServerArgsConfig
    )

    def model_post_init(self, __context: Any = None) -> None:
        if self.max_seq_len is not None and self.max_seq_len <= 0:
            raise ValueError("runtime.max_seq_len must be positive")
        if self.video_fps is not None and self.video_fps <= 0:
            raise ValueError("runtime.video_fps must be positive")


class PlacementConfig(BaseModel):
    """Pipeline-level placement planning limits."""

    model_config = ConfigDict(extra="forbid")

    max_total_gpu_memory_fraction_per_gpu: float = 1.0
    require_memory_fraction_for_colocation: bool = True

    def model_post_init(self, __context: Any = None) -> None:
        value = self.max_total_gpu_memory_fraction_per_gpu
        if not 0.0 < value <= 1.0:
            raise ValueError(
                "placement.max_total_gpu_memory_fraction_per_gpu must be in (0, 1]"
            )


class StageConfig(BaseModel):
    """Single pipeline stage configuration.

    Minimal example::

        StageConfig(name="decode", factory="...create_decode", terminal=True)

    Fan-in example::

        StageConfig(
            name="aggregate",
            factory="...create_aggregate",
            wait_for=["preprocessor", "image_enc", "audio_enc"],
            merge_fn="...merge_for_thinker",
            next="thinker",
        )
    """

    model_config = ConfigDict(extra="forbid")

    # --- Identity ---
    name: str

    # --- Factory ---
    factory: str
    factory_args: dict[str, Any] = Field(default_factory=dict)

    # --- Routing (set `next` for static routing or `terminal`) ---
    next: str | list[str] | None = None
    terminal: bool = False
    route_fn: str | None = None

    # --- GPU / parallelism ---
    gpu: int | list[int] | None = None
    tp_size: int = 1
    parallelism: ParallelismConfig = Field(default_factory=ParallelismConfig)
    process: str | None = None

    # --- Runtime intent ---
    runtime: StageRuntimeConfig = Field(default_factory=StageRuntimeConfig)
    runtime_arg_map: dict[str, str] = Field(default_factory=dict)

    # --- Fan-in ---
    wait_for: list[str] | None = None
    wait_for_fn: str | None = None
    merge_fn: str | None = None

    # --- Streaming ---
    stream_to: list[str] = Field(default_factory=list)
    stream_done_to_fn: str | None = None
    can_accept_stream_before_payload: bool = False

    # --- Payload transport ---
    disable_direct_cuda_ipc_payload: bool = False

    # --- Route-specific payload projection ---
    project_payload: dict[str, str] = Field(default_factory=dict)

    # --- Communication pool tuning ---
    comm: CommConfig | None = None

    def model_post_init(self, __context: Any = None) -> None:
        fields_set = self.__pydantic_fields_set__
        tp_size_set = "tp_size" in fields_set
        parallelism_set = "parallelism" in fields_set
        if self.tp_size < 1:
            raise ValueError(f"Stage {self.name!r} must have tp_size >= 1")
        if self.process is not None:
            self.process = self.process.strip()
            if not self.process:
                raise ValueError(f"Stage {self.name!r} process must not be empty")
        if parallelism_set and tp_size_set and self.parallelism.tp != self.tp_size:
            raise ValueError(
                f"Stage {self.name!r}: tp_size={self.tp_size} conflicts with "
                f"parallelism.tp={self.parallelism.tp}"
            )
        if not parallelism_set and self.tp_size != self.parallelism.tp:
            self.parallelism.tp = self.tp_size
        elif (
            parallelism_set and not tp_size_set and self.tp_size != self.parallelism.tp
        ):
            self.tp_size = self.parallelism.tp


class PipelineConfig(BaseModel):
    """Top-level pipeline configuration.

    Subclasses set ``requires_model_capabilities`` when their model package
    must export static architecture-level capability metadata.
    """

    model_config = ConfigDict(extra="forbid")

    architecture: ClassVar[str | None] = None
    architecture_aliases: ClassVar[tuple[str, ...]] = ()
    requires_model_capabilities: ClassVar[bool] = False
    tensor_parallel_disable_custom_all_reduce_stages: ClassVar[tuple[str, ...]] = ()
    required_speech_reference_count: ClassVar[int | None] = None
    speech_reference_text_required: ClassVar[bool] = False
    additional_speech_languages: ClassVar[frozenset[str]] = frozenset()

    model_path: str
    stages: list[StageConfig]
    name: str | None = None
    entry_stage: str | None = None
    fused_stages: list[list[str]] = Field(default_factory=list)
    runtime_overrides: dict[str, dict[str, Any]] = Field(default_factory=dict)
    env_defaults: dict[str, str] = Field(default_factory=dict)
    placement: PlacementConfig = Field(default_factory=PlacementConfig)
    placement_policy: str | None = None
    endpoints: EndpointsConfig = Field(default_factory=EndpointsConfig)
    terminal_stages_fn: str | None = None
    config_cls: str | None = None

    def model_post_init(self, __context: Any = None) -> None:
        self._validate_general()
        self._validate_fusion()
        self.config_cls = self.__class__.__name__
        if self.name is None:
            self.name = self.model_path

    @property
    def resolved_entry_stage(self) -> str:
        if self.entry_stage is not None:
            return self.entry_stage
        return self.stages[0].name

    @property
    def terminal_stages(self) -> list[str]:
        return [s.name for s in self.stages if s.terminal]

    @classmethod
    def mem_fraction_role_to_stage(cls) -> dict[str, str]:
        """Class-level public role map for SGLang mem_fraction_static overrides."""
        return {}

    @classmethod
    def encoder_mem_reserve_role_to_stage(cls) -> dict[str, str]:
        """Class-level public role map for encoder memory reserve overrides."""
        return {}

    @classmethod
    def talker_role_to_stage(cls) -> dict[str, str]:
        """Class-level public role map for talker placement overrides."""
        return {}

    @classmethod
    def talker_sglang_role_to_stage(cls) -> dict[str, str]:
        """Class-level public role map for talker SGLang ServerArgs overrides."""
        return {}

    @classmethod
    def generation_sglang_role_to_stage(cls) -> dict[str, str]:
        """Class-level public role map for generation SGLang ServerArgs overrides."""
        return {}

    @classmethod
    def code2wav_stage(cls) -> str | None:
        """Return the code2wav stage name when the pipeline supports it."""
        return None

    @classmethod
    def tensor_parallel_server_args_overrides(
        cls,
        *,
        stage_name: str,
        tp_size: int,
    ) -> dict[str, object]:
        """Return SGLang ServerArgs overrides implied by stage TP settings."""
        if (
            tp_size > 1
            and stage_name in cls.tensor_parallel_disable_custom_all_reduce_stages
        ):
            return {"disable_custom_all_reduce": True}
        return {}

    @classmethod
    def topology_gated_custom_all_reduce_stages(cls) -> set[str]:
        """Stages whose TP custom all-reduce disable is topology-relaxable."""
        return set()

    def requires_uploaded_voice_for_named_voice(self) -> bool:
        """Return whether non-default TTS voice names must be uploaded voices."""
        return False

    def supports_uploaded_voice_references(self) -> bool:
        """Return whether uploaded voices can be lowered as reference audio."""
        return False

    @property
    def gpu_placement(self) -> dict[str, int | list[int]]:
        out: dict[str, int | list[int]] = {}
        for s in self.stages:
            if s.gpu is not None:
                out[s.name] = s.gpu
        return out

    def _validate_general(self) -> None:
        if not self.model_path:
            raise ValueError("Model path is required")

        names = [s.name for s in self.stages]
        if not names:
            raise ValueError("Pipeline must define at least one stage")
        if len(names) != len(set(names)):
            raise ValueError("Stage names must be unique")
        entry = self.resolved_entry_stage
        if entry not in names:
            raise ValueError(f"entry_stage {entry!r} is not defined")

        for s in self.stages:
            if not s.factory:
                raise ValueError(f"Stage {s.name!r} missing factory")
            has_next = s.next is not None
            if has_next == bool(s.terminal):
                raise ValueError(
                    f"Stage {s.name!r} must set exactly one of 'next' or 'terminal'"
                )
            if s.terminal and s.route_fn is not None:
                raise ValueError(
                    f"Stage {s.name!r} cannot set route_fn on a terminal stage"
                )
            if s.stream_done_to_fn is not None and not s.stream_to:
                raise ValueError(
                    f"Stage {s.name!r} cannot set stream_done_to_fn without stream_to"
                )
            if s.tp_size < 1:
                raise ValueError(f"Stage {s.name!r} must have tp_size >= 1")
            if s.parallelism.tp != s.tp_size:
                raise ValueError(
                    f"Stage {s.name!r}: tp_size={s.tp_size} conflicts with "
                    f"parallelism.tp={s.parallelism.tp}"
                )
            if isinstance(s.gpu, list) and len(s.gpu) != s.tp_size:
                raise ValueError(
                    f"Stage {s.name!r}: gpu has {len(s.gpu)} entries "
                    f"but tp_size={s.tp_size}"
                )
            if s.wait_for:
                if not s.merge_fn:
                    raise ValueError(f"Stage {s.name!r} has wait_for but no merge_fn")
                unknown = set(s.wait_for) - set(names)
                if unknown:
                    raise ValueError(
                        f"Stage {s.name!r} wait_for has unknown stages: {sorted(unknown)}"
                    )
            elif s.wait_for_fn is not None:
                raise ValueError(f"Stage {s.name!r} has wait_for_fn but no wait_for")
            if s.next is not None:
                targets = [s.next] if isinstance(s.next, str) else s.next
                unknown = set(targets) - set(names)
                if unknown:
                    raise ValueError(
                        f"Stage {s.name!r} next has unknown stages: {sorted(unknown)}"
                    )
            for t in s.stream_to:
                if t not in names:
                    raise ValueError(
                        f"Stage {s.name!r} stream_to references unknown stage {t!r}"
                    )
            for t in s.project_payload:
                if t not in names:
                    raise ValueError(
                        f"Stage {s.name!r} project_payload references unknown stage {t!r}"
                    )

        for stage_name in self.runtime_overrides:
            if stage_name not in names:
                raise ValueError(
                    f"runtime_overrides references unknown stage {stage_name!r}"
                )

        missing_process = [
            s.name for s in self.stages if s.tp_size == 1 and not s.process
        ]
        if missing_process:
            raise ValueError(
                "Non-TP stages must declare process; "
                f"missing process for {missing_process}"
            )

    def _validate_fusion(self) -> None:
        names = [s.name for s in self.stages]
        fused = self.fused_stages or []
        if not fused:
            return
        index_map = {n: i for i, n in enumerate(names)}
        stage_by_name = {s.name: s for s in self.stages}
        seen: set[str] = set()
        for group in fused:
            if not group or len(group) < 2:
                raise ValueError("fused_stages groups must have at least 2 stage names")
            for n in group:
                if n not in index_map:
                    raise ValueError(f"fused stage {n!r} is not defined")
                if n in seen:
                    raise ValueError(f"stage {n!r} appears in multiple fused groups")
                seen.add(n)
            indices = [index_map[n] for n in group]
            if indices != list(range(indices[0], indices[0] + len(indices))):
                raise ValueError(f"fused group not adjacent/ordered: {group}")
            self._validate_fused_group_contract(group, stage_by_name)

    def _validate_fused_group_contract(
        self,
        group: list[str],
        stage_by_name: dict[str, StageConfig],
    ) -> None:
        stages = [stage_by_name[name] for name in group]

        for stage in stages:
            if stage.tp_size != 1:
                raise ValueError(
                    f"fused group {group} cannot include TP stage {stage.name!r}"
                )

        gpu_ids = {
            gpu_id for stage in stages for gpu_id in _stage_gpu_ids_for_fusion(stage)
        }
        if len(gpu_ids) > 1:
            raise ValueError(
                f"fused group {group} must fit on one GPU; got {sorted(gpu_ids)}"
            )

        for index, stage in enumerate(stages):
            if index > 0 and stage.wait_for:
                raise ValueError(
                    f"fused group {group} cannot include internal fan-in stage "
                    f"{stage.name!r}"
                )
            if index < len(stages) - 1:
                expected_next = group[index + 1]
                if stage.terminal or stage.route_fn is not None:
                    raise ValueError(
                        f"fused group {group} must be linear; internal stage "
                        f"{stage.name!r} cannot be terminal or dynamic-routed"
                    )
                if _target_list(stage.next) != [expected_next]:
                    raise ValueError(
                        f"fused group {group} must be linear; stage "
                        f"{stage.name!r} must route only to {expected_next!r}"
                    )

    def apply_fusion(self) -> tuple[list[StageConfig], dict[str, str], str]:
        name_map = {s.name: s.name for s in self.stages}
        return list(self.stages), name_map, self.resolved_entry_stage

    @staticmethod
    def from_dict(data: dict[str, Any]) -> PipelineConfig:
        return PipelineConfig(**data)


def _target_list(targets: str | list[str] | None) -> list[str]:
    if targets is None:
        return []
    if isinstance(targets, str):
        return [targets]
    return list(targets)


def _stage_gpu_ids_for_fusion(stage: StageConfig) -> tuple[int, ...]:
    gpu = stage.gpu
    if gpu is None:
        return ()
    if isinstance(gpu, int):
        return (gpu,)
    return tuple(int(gpu_id) for gpu_id in gpu)

import importlib
import logging
import pkgutil
from dataclasses import dataclass, field
from functools import lru_cache
from typing import AbstractSet, Dict, Type

from sglang_omni.config import PipelineConfig

logger = logging.getLogger(__name__)


def _iter_config_architectures(config_cls: Type[PipelineConfig]) -> list[str]:
    architectures: list[str] = []
    seen: set[str] = set()
    aliases = getattr(config_cls, "architecture_aliases", ())
    if isinstance(aliases, str):
        aliases = (aliases,)
    for arch in (getattr(config_cls, "architecture", None), *tuple(aliases or ())):
        if not arch or arch in seen:
            continue
        architectures.append(arch)
        seen.add(arch)
    return architectures


@lru_cache()
def import_pipeline_configs(
    package_name: str, config_path: str, strict: bool = False
) -> Dict[str, Type[PipelineConfig]]:
    # Import the package first so pkgutil can enumerate its model subpackages.
    package = importlib.import_module(package_name)
    model_arch_to_config_cls = {}

    for _, name, ispkg in pkgutil.iter_modules(package.__path__, package_name + "."):
        if not ispkg:
            continue
        try:
            importlib.import_module(name)
        except Exception as exc:
            if strict:
                raise
            logger.warning(f"Ignore import error when loading {name}: {exc}")
            continue
        config_module_name = f"{name}.{config_path}"
        try:
            config_module = importlib.import_module(config_module_name)
        except ModuleNotFoundError as exc:
            if exc.name == config_module_name:
                if strict:
                    raise
                logger.debug(f"Skipping {name}: no submodule {config_path}")
                continue
            if strict:
                raise
            logger.warning(
                f"Ignore import error when loading {config_module_name}: {exc}"
            )
            continue
        except ImportError as exc:
            if strict:
                raise
            logger.warning(
                f"Ignore import error when loading {config_module_name}: {exc}"
            )
            continue
        if not hasattr(config_module, "EntryClass"):
            raise AssertionError(
                f"Config module {name}.{config_path} must have an EntryClass"
            )
        config_cls = config_module.EntryClass
        for arch in _iter_config_architectures(config_cls):
            existing_config_cls = model_arch_to_config_cls.get(arch)
            if (
                existing_config_cls is not None
                and existing_config_cls is not config_cls
            ):
                raise ValueError(
                    f"Config for architecture {arch} is registered by both "
                    f"{existing_config_cls.__module__}.{existing_config_cls.__name__} "
                    f"and {config_cls.__module__}.{config_cls.__name__}"
                )
            model_arch_to_config_cls[arch] = config_cls
    return model_arch_to_config_cls


@dataclass
class _PipelineConfigRegistry:
    configs: Dict[str, Type[PipelineConfig]] = field(default_factory=dict)

    def register_config(
        self,
        package_name: str,
        config_path: str = "config",
        overwrite: bool = False,
        strict: bool = False,
    ) -> None:
        pipeline_configs = import_pipeline_configs(package_name, config_path, strict)

        if overwrite:
            self.configs.update(pipeline_configs)
        else:
            for arch, cfg_cls in pipeline_configs.items():
                if arch in self.configs:
                    raise ValueError(
                        f"Config for {arch} already registered in the pipeline config registry"
                    )
                else:
                    self.configs[arch] = cfg_cls

    def get_supported_archs(self) -> AbstractSet[str]:
        return self.configs.keys()

    def get_config(self, arch: str) -> Type[PipelineConfig]:
        if arch not in self.configs:
            raise ValueError(
                f"Config for {arch} not found in the pipeline config registry"
            )
        return self.configs[arch]

    def get_config_cls_by_name(self, name: str) -> Type[PipelineConfig]:
        for config_cls in self.configs.values():
            if config_cls.__name__ == name:
                return config_cls
            config_module = importlib.import_module(config_cls.__module__)
            variants = getattr(config_module, "Variants", {})
            for variant_cls in variants.values():
                if variant_cls.__name__ == name:
                    return variant_cls
        raise ValueError(
            f"Config class {name} not found in the pipeline config registry"
        )


PIPELINE_CONFIG_REGISTRY = _PipelineConfigRegistry()
PIPELINE_CONFIG_REGISTRY.register_config("sglang_omni.models", "config")

